class Solution {
    public int getKth(int lo, int hi, int k) {
        int[] powers = new int[hi - lo + 1];
        for (int i = lo; i <= hi; i++) {
            int x = i;
            int power = 0;
            while (x != 1) {
                if (x % 2 == 0) x /= 2;
                else x = 3 * x + 1;
                power++;
            }
            powers[i - lo] = power;
        }
        Integer[] nums = new Integer[hi - lo + 1];
        for (int i = lo; i <= hi; i++) {
            nums[i - lo] = i;
        }
        Arrays.sort(nums, (a, b) -> powers[a - lo] == powers[b - lo] ? a - b : powers[a - lo] - powers[b - lo]);
        return nums[k - 1];
    }
}
